package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertThrows;

import java.io.IOException;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class CSVFormatPrintAndEscapeTest {

    private CSVFormat csvFormat;
    private Method printAndEscapeMethod;

    @BeforeEach
    void setUp() throws NoSuchMethodException {
        // Use DEFAULT CSVFormat instance for tests
        csvFormat = CSVFormat.DEFAULT;

        // Access private method printAndEscape using reflection
        printAndEscapeMethod = CSVFormat.class.getDeclaredMethod("printAndEscape", CharSequence.class, int.class, int.class, Appendable.class);
        printAndEscapeMethod.setAccessible(true);
    }

    @Test
    void testPrintAndEscape_noSpecialChars_appendsWholeSegment() throws Throwable {
        String input = "simpletext";
        StringBuilder out = new StringBuilder();

        printAndEscapeMethod.invoke(csvFormat, input, 0, input.length(), out);

        assertEquals("simpletext", out.toString());
    }

    @Test
    void testPrintAndEscape_withDelimiterChar_escapesDelimiter() throws Throwable {
        // delimiter is comma in DEFAULT
        String input = "abc,def";
        StringBuilder out = new StringBuilder();

        printAndEscapeMethod.invoke(csvFormat, input, 0, input.length(), out);

        // Expect "abc" + escape + "," + "def"
        // escape char is double quote in DEFAULT
        assertEquals("abc\"\,def", out.toString());
    }

    @Test
    void testPrintAndEscape_withEscapeChar_escapesEscape() throws Throwable {
        // escape char is double quote in DEFAULT
        String input = "abc\"def";
        StringBuilder out = new StringBuilder();

        printAndEscapeMethod.invoke(csvFormat, input, 0, input.length(), out);

        // Expect "abc" + escape + '"' + "def"
        assertEquals("abc\"\"def", out.toString());
    }

    @Test
    void testPrintAndEscape_withCR_and_LF_escapesWith_r_and_n() throws Throwable {
        String input = "line1\r\nline2";
        StringBuilder out = new StringBuilder();

        printAndEscapeMethod.invoke(csvFormat, input, 0, input.length(), out);

        // CR replaced by 'r', LF replaced by 'n', both preceded by escape char '"'
        assertEquals("line1\"r\"nline2", out.toString());
    }

    @Test
    void testPrintAndEscape_withOffsetAndLen_partialInput() throws Throwable {
        String input = "xxxabc,defyyy";
        StringBuilder out = new StringBuilder();

        // offset 3, length 7 -> "abc,def"
        printAndEscapeMethod.invoke(csvFormat, input, 3, 7, out);

        assertEquals("abc\"\,def", out.toString());
    }

    @Test
    void testPrintAndEscape_emptyInput_noOutput() throws Throwable {
        String input = "";
        StringBuilder out = new StringBuilder();

        printAndEscapeMethod.invoke(csvFormat, input, 0, 0, out);

        assertEquals("", out.toString());
    }

    @Test
    void testPrintAndEscape_appendableThrowsIOException() throws Throwable {
        CharSequence input = "abc";
        Appendable throwingAppendable = Mockito.mock(Appendable.class);
        Mockito.doThrow(new IOException("fail")).when(throwingAppendable).append(Mockito.any(CharSequence.class), Mockito.anyInt(), Mockito.anyInt());

        InvocationTargetException thrown = assertThrows(InvocationTargetException.class, () ->
            printAndEscapeMethod.invoke(csvFormat, input, 0, input.length(), throwingAppendable)
        );
        // Cause should be IOException
        assertEquals(IOException.class, thrown.getCause().getClass());
    }
}
